class Graph:
    def __init__(self):
        self.adj_list = {}

    def add_vertex(self, vertex):
        if vertex not in self.adj_list:
            self.adj_list[vertex] = []

    def add_edge(self, u, v, directed=False):
        self.add_vertex(u)
        self.add_vertex(v)

        self.adj_list[u].append(v)

        if not directed:
            self.adj_list[v].append(u)

    def get_neighbors(self, vertex):
        return self.adj_list.get(vertex, [])

    def display(self):
        for vertex, neighbors in self.adj_list.items():
            print(f"{vertex}: {neighbors}")

if __name__ == "__main__":
    g = Graph()

    g.add_vertex("A")
    g.add_vertex("B")
    g.add_vertex("C")
    g.add_vertex("D")

    g.add_edge("A", "B")
    g.add_edge("A", "C", directed=True) 
    g.add_edge("B", "D")
    g.add_edge("C", "D")
    g.add_edge("D", "A", directed=True)

    g.display()
    print("\nNeighbors of A:", g.get_neighbors("A"))
    print("Neighbors of C:", g.get_neighbors("C"))
    print("Neighbors of E:", g.get_neighbors("E"))
